.darma-loader-darma-custom-335 {color: var(--loader-color, #7c3aed);
  --loader-secondary-color: #c084fc;
  --loader-bg: #ffffff;
  height: 70px;
  aspect-ratio: 1;
  padding: 10px;
  border-radius: 20px;
  box-sizing: border-box;
  position: relative;
  mask: conic-gradient(currentColor 0 0) content-box exclude,conic-gradient(currentColor 0 0);
  filter: blur(12px);
  animation: darma-loader-darma-custom-335-l4-0 1.2s linear infinite alternate;
}.darma-loader-darma-custom-335:before {content: "";
  position: absolute;
  inset: 0;
  background: repeating-conic-gradient(#0000 0 5%,var(--loader-color, #7c3aed),#0000 20% 50%);
  animation: darma-loader-darma-custom-335-l4-1 1s linear infinite;
}@keyframes darma-loader-darma-custom-335-l4-0 {to {border-radius: 50%}}@keyframes darma-loader-darma-custom-335-l4-1 {to {rotate: .5turn}}

